8	-- -------------------------------------------------------------------------------------------------
9	
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library vunit_lib;
15	use vunit_lib.check_pkg.all;
16	use vunit_lib.run_pkg.all;
17	
18	library osvvm;
19	use osvvm.RandomPkg.RandomPType;
20	
21	use work.axi_stream_pkg.all;
22	
23	
24	entity tb_axi_stream_pkg is
25	  generic (
26	    data_width : positive range 1 to axi_stream_data_sz;
27	    user_width : natural range 0 to axi_stream_user_sz;
28	    runner_cfg : string
29	  );
30	end entity;
31	
32	architecture tb of tb_axi_stream_pkg is
33	begin
34	
35	  main : process
36	    variable rnd : RandomPType;
37	
38	    procedure test_slv_conversion(iteration : natural) is
39	      constant offset_max : integer := 73;
40	
41	      variable data : axi_stream_m2s_t := axi_stream_m2s_init;
42	      variable data_converted : std_ulogic_vector(
43	        axi_stream_m2s_sz(data_width=>data_width, user_width=>user_width) - 1 downto 0) :=
44	        (others => '0');
45	      variable data_slv : std_ulogic_vector(data_converted'high + offset_max downto 0) :=
46	        (others => '0');
47	
48	      variable hi, lo : integer := 0;
49	    begin
50	      -- Slice slv input, to make sure that ranges don't have to be down to 0
51	      lo := iteration mod offset_max;
52	
53	      hi := data_converted'high + lo;
54	      data_slv(hi downto lo) := rnd.RandSLV(data_converted'length);
55	      data := to_axi_stream_m2s(
56	        data_slv(hi downto lo),
57	        data_width=>data_width,
58	        user_width=>user_width,
59	        valid => '1');
60	      data_converted := to_slv(data, data_width=>data_width, user_width=>user_width);
61	
62	      check_equal(data_converted, data_slv(hi downto lo));
63	
64	    end procedure;
65	
66	  begin
67	    test_runner_setup(runner, runner_cfg);
68	    rnd.InitSeed(get_string_seed(runner_cfg));
69	
70	    if run("test_slv_conversion") then
71	
72	      for iteration in 0 to 1000 loop
73	        -- Loop a couple of times to get good random coverage
74	        test_slv_conversion(iteration);
75	      end loop;
76	
77	    end if;
78	
79	    test_runner_cleanup(runner);
80	  end process;
