10	library ieee;
11	use ieee.std_logic_1164.all;
12	
13	library osvvm;
14	use osvvm.RandomPkg.RandomPType;
15	
16	library vunit_lib;
17	use vunit_lib.check_pkg.all;
18	use vunit_lib.integer_array_pkg.all;
19	use vunit_lib.queue_pkg.all;
20	use vunit_lib.random_pkg.all;
21	use vunit_lib.run_pkg.all;
22	use vunit_lib.run_types_pkg.all;
23	
24	library bfm;
25	use bfm.stall_bfm_pkg.stall_configuration_t;
26	
27	library common;
28	
29	
30	entity tb_axi_stream_bfm is
31	  generic (
32	    data_width : positive;
33	    runner_cfg : string
34	  );
35	end entity;
36	
37	architecture tb of tb_axi_stream_bfm is
38	
39	  -- Generics
40	  constant drive_invalid_value : std_ulogic := 'X';
41	
42	  -- DUT connections
43	  constant clk_period : time := 10 ns;
44	  signal clk : std_ulogic := '0';
45	
46	  signal ready, valid, last : std_ulogic := '0';
47	  signal data : std_ulogic_vector(data_width - 1 downto 0) := (others => '0');
48	  signal strobe : std_ulogic_vector(data_width / 8 - 1 downto 0) := (others => '0');
49	
50	  -- Testbench stuff
51	  shared variable rnd : RandomPType;
52	
53	  impure function get_stall_probability_percent return natural is
54	  begin
55	    return rnd.Uniform(0, 90);
56	  end function;
57	
58	  impure function init_and_get_stall_probability_percent return natural is
59	  begin
60	    -- This is the first function that is called, so we initialize the random number generator here.
61	    rnd.InitSeed(get_string_seed(runner_cfg));
62	
63	    return get_stall_probability_percent;
64	  end function;
65	  constant master_stall_probability_percent : natural := init_and_get_stall_probability_percent;
66	  constant slave_stall_probability_percent : natural := get_stall_probability_percent;
67	
68	  constant master_stall_config : stall_configuration_t := (
69	    stall_probability => real(master_stall_probability_percent) / 100.0,
70	    min_stall_cycles => 1,
71	    max_stall_cycles => 3
72	  );
73	
74	  constant slave_stall_config : stall_configuration_t := (
75	    stall_probability => real(slave_stall_probability_percent) / 100.0,
76	    min_stall_cycles => 1,
77	    max_stall_cycles => 3
78	  );
79	
80	  constant input_data_queue, reference_data_queue : queue_t := new_queue;
81	
82	  signal num_packets_checked : natural := 0;
83	
84	begin
85	
86	  test_runner_watchdog(runner, 2 ms);
87	  clk <= not clk after clk_period / 2;
88	
89	
90	  ------------------------------------------------------------------------------
91	  main : process
92	    variable num_packets_expected : natural := 0;
93	
94	    procedure test_random_packet is
95	      variable data_packet, data_packet_copy : integer_array_t := null_integer_array;
96	    begin
97	      random_integer_array(
98	        rnd=>rnd,
99	        integer_array=>data_packet,
100	        width=>rnd.RandInt(1, 30),
101	        bits_per_word => 8,
102	        is_signed => false
103	      );
104	      data_packet_copy := copy(data_packet);
105	
106	      push_ref(input_data_queue, data_packet);
107	      push_ref(reference_data_queue, data_packet_copy);
108	
109	      num_packets_expected := num_packets_expected + 1;
110	    end procedure;
111	
112	    procedure test_signed_vs_unsigned is
113	      variable data_packet_unsigned : integer_array_t := new_1d(
114	        length=>1, bit_width=>8, is_signed=>false
115	      );
116	      variable data_packet_signed : integer_array_t := new_1d(
117	        length=>1, bit_width=>8, is_signed=>true
118	      );
119	    begin
120	      set(arr=>data_packet_unsigned, idx=>0, value=>255);
121	      set(arr=>data_packet_signed, idx=>0, value=>-1);
122	
123	      -- Stream master does not support signed data yet.
124	      push_ref(input_data_queue, data_packet_unsigned);
125	      -- Slave does though.
126	      push_ref(reference_data_queue, data_packet_signed);
127	
128	      num_packets_expected := num_packets_expected + 1;
